"use strict";exports.id=8921,exports.ids=[8921],exports.modules={98921:a=>{a.exports=JSON.parse('{"source":"COFEPRIS","documentId":"NOM-259-SSA1-2012 + LFPUB","version":"2012-12","description":"墨西哥化妆品功效宣称和广告法规","rules":[{"ruleId":"MX-CLAIM-001","category":"claim","target":"医疗治疗/消炎抗菌","aliases":["curar","治愈","antibacteriano","抗菌","antimicrobiano","抑菌","antiinflamatorio","消炎","tratamiento m\xe9dico","医学治疗","elimina acne","去除痤疮","cura heridas","愈合伤口"],"severity":"critical","condition":"禁止化妆品宣称医疗治疗功效","message":"化妆品不得使用\'治愈\'、\'消炎\'、\'抗菌\'等医疗术语，不得宣称治疗痤疮、伤口愈合等药品功效","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-002","category":"claim","target":"无添加/纯天然夸大","aliases":["100% natural","100%天然","sin qu\xedmicos","无化学成分","sin conservantes","无防腐剂","org\xe1nico","有机","comestible","可食用","food grade","食品级"],"severity":"warning","condition":"禁止绝对化无添加/纯天然宣称","message":"避免使用\'100%天然\'、\'无化学成分\'等绝对化表述，天然成分宣称需有科学依据","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-003","category":"claim","target":"防晒绝对化宣称","aliases":["protecci\xf3n total contra UV","全面防紫外线","bloqueador total","完全阻隔","sin necesidad de reaplicar","无需补涂","protecci\xf3n 100%","100%防晒"],"severity":"critical","condition":"禁止防晒绝对化和无需补涂宣称","message":"防晒产品必须标注SPF值和UVA/UVB防护，禁止使用\'全面防护\'、\'无需补涂\'等绝对化表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-004","category":"claim","target":"无风险/绝不致敏","aliases":["sin ning\xfan riesgo","无任何风险","no causa irritaci\xf3n","绝不致敏","hipoalerg\xe9nico sin pruebas","无测试低致敏","seguro para todo el mundo","人人安全可用"],"severity":"warning","condition":"禁止无依据的安全绝对化宣称","message":"安全宣称需有测试支持，不得使用\'无任何风险\'、\'绝不致敏\'等绝对化表述，低致敏需临床验证","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-005","category":"claim","target":"抗皱/抗衰老绝对化","aliases":["elimina arrugas completamente","完全消除皱纹","anti-envejecimiento total","全面抗衰老","rejuvenece 10 a\xf1os","年轻10岁","paraliza el envejecimiento","停止衰老"],"severity":"critical","condition":"禁止抗衰老绝对化宣称","message":"禁止使用\'完全消除皱纹\'、\'全面抗衰老\'等绝对化表述，建议使用\'改善皱纹外观\'等温和表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-006","category":"claim","target":"FDA批准误导","aliases":["FDA aprobado","FDA批准","FDA certificado","FDA认证","aproximaci\xf3n farmac\xe9utica","药品级"],"severity":"warning","condition":"禁止误导性FDA相关宣称","message":"禁止误导消费者使用FDA批准标识，墨西哥产品需符合COFEPRIS规定，不得暗示药品级属性","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-007","category":"claim","target":"dermatologist tested","aliases":["Dermatologist tested","Testeado por dermat\xf3logo","皮肤科医生测试","dermatol\xf3gicamente comprobado","皮肤科验证"],"severity":"info","condition":"需真实有效测试报告","message":"如宣称dermatologist tested，需有实际测试报告支持，测试机构需具备资质","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-008","category":"claim","target":"hypoallergenic","aliases":["Hipoalerg\xe9nico","低致敏","无过敏","menos irritante","低刺激"],"severity":"warning","condition":"需有临床测试支持","message":"低致敏宣称需有临床测试支持，不可滥用，需明确测试方法和结果","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-009","category":"claim","target":"no animal testing","aliases":["No tested on animals","Sin pruebas en animales","无动物测试","cruelty free","无残忍测试"],"severity":"info","condition":"需有证明文件","message":"无动物测试宣称需有供应链证明文件，符合墨西哥动物保护法规要求","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-010","category":"claim","target":"治愈/根治","aliases":["Cure","Curar","治愈","根治","elimina por completo","完全根除","resuelve definitivamente","彻底解决"],"severity":"critical","condition":"禁止任何治愈宣称","message":"化妆品不得使用任何\'治愈\'、\'根治\'等医疗用语，不得暗示治疗疾病功能","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-011","category":"claim","target":"去除脂肪团","aliases":["Cellulite removal","Eliminaci\xf3n de celulitis","去橘皮","燃脂","quema grasas","脂肪燃烧","reduce celulitis completamente","完全消除橘皮"],"severity":"critical","condition":"禁止宣称去除脂肪团","message":"化妆品不得宣称可以去除脂肪团（橘皮组织），此类宣称属于药品功效范畴","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-012","category":"claim","target":"丰胸","aliases":["Breast enlargement","Aumento de senos","隆胸","丰乳","aumenta el tama\xf1o de senos","增大乳房","mejora la firmeza permanentemente","永久提升胸部"],"severity":"critical","condition":"禁止任何丰乳宣称","message":"化妆品不得宣称具有丰胸或改变胸部大小的效果，此类宣称需药品注册","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-013","category":"claim","target":"永久/彻底根治","aliases":["permanente","永久","definitivo","彻底","根治","eliminar permanentemente","永久消除","para siempre","永远","resultados duraderos garantizados","保证持久效果"],"severity":"critical","condition":"禁止绝对化永久功效宣称","message":"禁止使用\'永久\'、\'彻底根治\'、\'永远\'等绝对化功效宣称，建议使用\'有助于维持\'等表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-014","category":"claim","target":"快速见效/7天","aliases":["7 d\xedas","7天","ultra r\xe1pido","超快速","resultados inmediatos","结果立竿见影","garantizado","保证结果","100% efectivo","100%有效","instant\xe1neamente","即刻见效"],"severity":"critical","condition":"禁止承诺具体时效和绝对效果","message":"禁止使用具体时间承诺（如\'7天\'）和绝对效果保证，功效宣称需基于科学验证","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-015","category":"claim","target":"医疗级/医学配方","aliases":["f\xf3rmula m\xe9dica","医学配方","医疗级","grado m\xe9dico","medical grade","f\xf3rmula exclusiva","独家配方","cl\xednica","临床级","tratamiento profesional","专业治疗"],"severity":"critical","condition":"禁止医疗化宣称","message":"禁止使用\'医疗级\'、\'医学配方\'、\'临床级\'等暗示药品功效的宣传，化妆品不得模仿药品宣传","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-016","category":"claim","target":"特殊人群宣称","aliases":["beb\xe9s","婴儿","mujeres embarazadas","孕妇","embarazada","ni\xf1os","儿童","para todo tipo de piel","适合所有皮肤类型","beb\xe9s y mujeres embarazadas","婴幼儿可用","孕妇可用","para reci\xe9n nacidos","新生儿可用"],"severity":"critical","condition":"特殊人群需特殊审批","message":"禁止随意宣称适合婴儿、孕妇等特殊人群，需标注适用年龄，特殊人群产品需单独注册","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-017","category":"claim","target":"彻底祛斑/美白","aliases":["elimina todas las manchas","消除所有斑点","mejor que","优于","\xfanico","唯一有效","独家","piel blanca para siempre","让皮肤永远变白","blanqueamiento permanente","永久美白","elimina melanina completamente","完全消除黑色素"],"severity":"critical","condition":"禁止绝对化美白宣称","message":"禁止使用\'彻底祛斑\'、\'永久美白\'、\'永远变白\'等绝对化功效宣称，美白产品需符合COFEPRIS成分限制","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-018","category":"claim","target":"防脱发/生发","aliases":["previene ca\xedda del cabello","防止脱发","promueve crecimiento capilar","促进头发生长","reanuda crecimiento","重新生发","detiene ca\xedda","停止掉发"],"severity":"critical","condition":"禁止防脱发/生发宣称","message":"化妆品不得宣称防脱发或促进头发生长功效，此类宣称属于药品范畴","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-019","category":"claim","target":"排毒/净化绝对化","aliases":["detoxifica la piel","皮肤排毒","limpia por dentro","内部清洁","elimina toxinas completamente","完全清除毒素","purifica profundamente","深层净化"],"severity":"warning","condition":"禁止无依据的排毒宣称","message":"避免使用\'排毒\'、\'净化\'等暗示医疗功效的表述，建议使用\'清洁\'、\'去除杂质\'等温和表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-020","category":"claim","target":"价格/性价比绝对化","aliases":["mejor precio","最优价格","precio m\xe1s bajo","最低价格","inigualable valor","无与伦比的价值","oferta \xfanica","独家优惠"],"severity":"info","condition":"禁止价格绝对化宣称","message":"价格宣称需真实可验证，不得使用\'最低价格\'、\'最优性价比\'等绝对化表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-021","category":"claim","target":"细胞再生/修复","aliases":["regenera c\xe9lulas","细胞再生","repara tejidos","修复组织","recupera弹性","恢复弹性","renueva la piel completamente","完全焕新皮肤"],"severity":"critical","condition":"禁止细胞再生等医疗级修复宣称","message":"化妆品不得宣称细胞再生、组织修复等医疗功效，建议使用\'改善皮肤外观\'等表述","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"},{"ruleId":"MX-CLAIM-022","category":"claim","target":"对比/贬低竞品","aliases":["mejor que el competidor","优于竞争对手","sin igual en el mercado","市场上无与伦比","supera a todos los dem\xe1s","超越所有其他产品","m\xe1s eficaz que","比...更有效"],"severity":"warning","condition":"禁止对比贬低竞品","message":"禁止使用贬低竞争对手或与其他产品对比的宣传用语，宣传需专注自身产品特性","sourceUrl":"https://www.dof.gob.mx/nota_detalle.php?codigo=5325961&fecha=05/12/2012"}]}')}};